package com.example.attendance.entity;import jakarta.persistence.*;import java.time.LocalDate;@Entity public class StudentAttendance{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;private String studentName;private String course;private LocalDate date;private boolean present;public Long getId(){return id;}public String getStudentName(){return studentName;}public void setStudentName(String s){this.studentName=s;}public String getCourse(){return course;}public void setCourse(String c){this.course=c;}public LocalDate getDate(){return date;}public void setDate(LocalDate d){this.date=d;}public boolean isPresent(){return present;}public void setPresent(boolean p){this.present=p;}}